const status = $json.status;
const d = $json.date || 'unknown';
if (status === 'not_found') {
  console.log(`ℹ️ No planner found for ${d} — skipping sync`);
} else if (status === 'no_annotations') {
  console.log(`ℹ️ No annotations yet for ${d} — skipping sync`);
} else if ($json.error) {
  console.warn(`⚠️ Render service error for ${d}: ${$json.error}`);
} else {
  console.warn(`⚠️ Render returned unexpected status '${status}' for ${d}`);
}
return [];

