// Extract and parse the JSON from Claude's response
const content = $json.choices[0].message.content.trim();
const stripped = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(stripped);
} catch (e) {
  throw new Error('Vision model returned unparseable JSON: ' + e.message + '\nRaw: ' + content);
}

const todos = parsed.todos || [];
const date  = $('Render Planner PNG').first().json.date;
console.log(`🔍 Recognized ${todos.length} todo item(s) for ${date}`);

return [{ json: { todos, date } }];

// Merge recognized todos with current HA state and produce a list of actions.
// Each returned item represents one HA service call to make.
const recognized = $('Parse Vision Response').first().json;
const todos       = recognized.todos || [];
const date        = recognized.date;

// Current HA items (for duplicate detection on handwritten entries)
const haResponse  = $json;
const currentItems = haResponse?.['todo.tasks']?.items ?? [];
const currentTexts = new Set(currentItems.map(i => (i.summary || '').trim().toLowerCase()));

const actions = [];

for (const todo of todos) {
  const text = (todo.text || '').trim();
  if (!text) continue;

  if (todo.source === 'printed' && todo.checked) {
    // Mark existing HA task as completed
    actions.push({ json: { _action: 'complete', item: text, date } });

  } else if (todo.source === 'handwritten') {
    if (currentTexts.has(text.toLowerCase())) {
      console.log(`⏭️ Skipping duplicate: "${text}"`);
      continue;
    }
    // Add new handwritten task; flag if it was already checked off
    actions.push({ json: { _action: 'add', item: text, checked: todo.checked, date } });
    currentTexts.add(text.toLowerCase()); // prevent duplicates within same run
  }
}

if (actions.length === 0) {
  console.log(`ℹ️ No HA changes needed for ${date}`);
  return [];
}

const completions = actions.filter(a => a.json._action === 'complete').length;
const additions   = actions.filter(a => a.json._action === 'add').length;
console.log(`📋 ${date}: ${completions} completion(s), ${additions} addition(s) to apply`);

return actions;
